SELECT su.age, su.nick_name as nickName, su.sex, su.phonenumber as phone, ueit_exception.*
FROM sys_user su
JOIN ueit_exception ON su.user_id = ueit_exception.user_id

     and su.user_id = #{userId}
    AND su.phonenumber  like concat('%', #{phone}, '%')
    AND ueit_exception.type = #{type}
    AND ueit_exception.state = #{state}
    AND ueit_exception.create_time BETWEEN #{startCreateTime} AND #{endCreateTime}

order by ueit_exception.id desc

select id, user_id, device_id, type, value, longitude, latitude, state, create_time as readTime, update_by, update_time, update_content, location from ueit_exception

     and user_id = #{userId}
     and create_time BETWEEN #{beginReadTime} AND #{endReadTime}

SELECT su.age, su.nick_name as nickName, su.sex, su.phonenumber as phone, ueit_exception.id, ueit_exception.user_id, ueit_exception.device_id, ueit_exception.type, ueit_exception.value, ueit_exception.longitude, ueit_exception.latitude, ueit_exception.state, ueit_exception.create_time as readTime, ueit_exception.update_by, ueit_exception.update_time, ueit_exception.update_content, ueit_exception.location FROM sys_user su JOIN ueit_exception ON su.user_id = ueit_exception.user_id
AND ueit_exception.type = #{type}
order by ueit_exception.id desc limit 10

SELECT COUNT(*) AS total
FROM ueit_exception

    user_id IS NOT NULL
    AND ueit_exception.type = #{type}

GROUP BY type;

SELECT su.age, su.nick_name as nickName, su.sex, su.phonenumber as phone,
ueit_exception.id, ueit_exception.user_id as userIdWho, ueit_exception.device_id, ueit_exception.type, ueit_exception.value, ueit_exception.longitude, ueit_exception.latitude, ueit_exception.state, ueit_exception.create_time as readTime, ueit_exception.update_by as updateByWho, ueit_exception.update_time as updateTimeWho, ueit_exception.update_content, ueit_exception.location
FROM sys_user su
JOIN ueit_exception ON su.user_id = ueit_exception.user_id

     and su.user_id = #{userId}
    AND su.phonenumber  like concat('%', #{phone}, '%')
    AND ueit_exception.type = #{type}
    AND ueit_exception.state = #{state}
    AND ueit_exception.create_time BETWEEN #{startCreateTime} AND #{endCreateTime}

order by ueit_exception.id desc

mapper.update:
update ueit_exception
state = 1, user_id = #{userId}, device_id = #{deviceId}, type = #{type}, value = #{value}, longitude = #{longitude}, latitude = #{latitude}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, update_content = #{updateContent}, location = #{location},
where id = #{id}
